#' @importFrom rvest read_html html_element html_table
#' @importFrom dplyr row_number
get_uhslc <- function(storm,dpath=NULL){
  if(is.null(dpath)) dpath=tempdir()
  if (!dir.exists(paste0(dpath,"/UHSLC/"))) dir.create(paste0(dpath,"/UHSLC"))
  stormdates <- as.POSIXct(storm$ISO_TIME,tz="GMT")
  dpath <- paste0(dpath,"/UHSLC")
  stations <- UHSLC_stats()|>
    mutate(startdate=as.POSIXct(startdate,tz="GMT"),
           stopdate=as.POSIXct(stopdate,tz="GMT"),
           UHid= sprintf("%03d", as.numeric(UHid)))
  roci <- storm |> pull(contains("CONS_ROCI"))|>mean(na.rm=TRUE)
  if (is.na(roci)) roci=500000/1852
  if (!class(storm)[1]=="sf") storm <- st_as_sf(storm,coords=c("LON","LAT"),crs=4326)
  extnt <- st_transform(st_union(st_geometry(st_buffer(storm,as.numeric(roci)*1852))),4326)
  stats <- stations |>
    st_as_sf(coords=c("Lon","Lat"),crs=4326) |>
    st_crop(extnt) |>
    filter(startdate<min(as.POSIXct(storm$ISO_TIME,tz="GMT")),
           stopdate>max(as.POSIXct(storm$ISO_TIME,tz="GMT")))
  if (nrow(stats)>0){
    obs <- lapply(1:nrow(stats), function(x){
      attempt=0;success=FALSE
      cat("\rDownloading/loading UHSLC water level data: %",round(100*x/nrow(stats),1))
      url <- paste0("https://uhslc.soest.hawaii.edu/data/csv/fast/hourly/h",stats$UHid[x],".csv")
      df <- paste0(dpath,"/h",stats$UHid[x],".csv")
      if (file.exists(df)){ dat=read.csv(df)}
      else{
        while(attempt < 3 && !success) {
          attempt <- attempt + 1
          dat <- tryCatch({
            dat <- read.csv(url)
            names(dat) <- c("year","month","day","hour","obs")
            write.csv(dat,df,row.names=FALSE)
            success <- TRUE
            dat
          }, error = function(e){
            if (attempt >= 3) {
              return(NULL)
            }else{
              Sys.sleep(0.5)
            }
          })
        }
      }
      dat <- dat|>
        filter(obs>0)|>
        mutate(time= as.POSIXct(paste(paste(year,month,day,sep="-"),hour),format="%Y-%m-%d %H",tz="GMT"),
               Jday =format(time,"%j"),
               meanSL = mean(obs,na.rm=TRUE),
               relWL =(obs-meanSL)/1000,
               lat = st_coordinates(stats[x,])[,2],
               lon = st_coordinates(stats[x,])[,1],
               UHid = stats$UHid[x],
               GLid = stats$GLid[x])|>
        group_by(Jday) |>
        mutate(HT = max(relWL,na.rm=TRUE))|>
        ungroup()|>
        mutate(MSL = mean(relWL[time<min(stormdates,na.rm=TRUE)|time>max(stormdates,na.rm=TRUE)],na.rm=TRUE),
               MHT = mean(HT[time<min(stormdates,na.rm=TRUE)|time>max(stormdates,na.rm=TRUE)],na.rm=TRUE))|>
        filter(time>=min(stormdates),time<=max(stormdates))
      dat
    })
  }else{return(NULL)}
  cat("\r", paste(rep(" ", 50), collapse=""), "\r")
  dat <- do.call(rbind,obs)
  dat <- dat |>
    st_as_sf(coords=c("lon","lat"),crs=4326)|>
    ungroup()
  dat
}
get_jasl <- function(storm,dpath=NULL){
  if(is.null(dpath)) dpath=tempdir()
  if (!dir.exists(paste0(dpath,"/JASL/"))) dir.create(paste0(dpath,"/JASL"))
  stormdates <- as.POSIXct(storm$ISO_TIME,tz="GMT")
  dpath <- paste0(dpath,"/JASL")
  page <- tryCatch({
      read_html("https://ftp.soest.hawaii.edu/uhslc/rqds/")|>
      html_element("table") |>
      html_table() |>
      rename(GL='GL#',ST='ST#')
    }, error = function(e){
      JASL_stats()
    })
  stations <- page |>
    mutate(Lat = strsplit(Lat,"-"),
           Long = strsplit(Long,"-"),
           dates=strsplit(QCyrs,"-"))|>
    group_by(ST)|>
    mutate(STid = paste0(sprintf("%03d", as.numeric(ST)),letters[row_number()]))|>
    ungroup()

  Lats <- (ifelse(grepl("S",sapply(stations$Lat,"[[",2)),-1,1))*as.numeric(sapply(stations$Lat,"[[",1)) +
    as.numeric(gsub("N|S","",sapply(stations$Lat,"[[",2)))/60
  Longs <- (ifelse(grepl("W",sapply(stations$Long,"[[",2)),-1,1))*as.numeric(sapply(stations$Long,"[[",1)) +
    as.numeric(gsub("W|E","",sapply(stations$Long,"[[",2)))/60
  stations$Lat <- Lats
  stations$Long <- Longs
  stations$mindate=as.POSIXct(paste0(sapply(stations$dates,"[[",1),"-01-01"))
  stations$maxdate=as.POSIXct(paste0(sapply(stations$dates,"[[",2),"-12-31"))
  roci <- storm |> pull(contains("CONS_ROCI"))|>mean(na.rm=TRUE)
  if (is.na(roci)) roci=500000/1852
  if (!class(storm)[1]=="sf") storm <- st_as_sf(storm,coords=c("LON","LAT"),crs=4326)
  extnt <- st_transform(st_union(st_geometry(st_buffer(storm,as.numeric(roci)*1852))),4326)
  stats <- stations |>
    st_as_sf(coords=c("Long","Lat"),crs=4326) |>
    st_crop(extnt) |>
    filter(mindate<min(as.POSIXct(storm$ISO_TIME,tz="GMT")),
           maxdate>max(as.POSIXct(storm$ISO_TIME,tz="GMT")))
  if (nrow(stats)>0){
    obs <- lapply(1:nrow(stats), function(x){
      attempt=0;success=FALSE
      url <- paste0("http://uhslc.soest.hawaii.edu/opendap/rqds/global/hourly/h",stats$STid[x],".nc")
      df <- paste0(dpath,"/h",stats$STid[x],".csv")
      if (file.exists(df)){ return(read.csv(df))}
      else{
        while(attempt < 3 && !success) {
          attempt <- attempt + 1
          nc <- tryCatch({
            nc <- ncdf4::nc_open(url)
            success <- TRUE
            nc
          }, error = function(e){
            if (attempt >= 3) {
              return(NULL)
            }else{
              Sys.sleep(0.5)
            }
          })
        }
      }
      ncsv <- data.frame(obs=ncdf4::ncvar_get(nc,"sea_level"),time=as.POSIXct("1800-01-01")+ncdf4::ncvar_get(nc,"time")*24*60*60)

      ncsv$day <- format(ncsv$time,"%j")
      ncsv$obs <- ncsv$obs-ncdf4::ncvar_get(nc,"reference_offset")
      ncsv$meanSL <- mean(ncsv$obs,na.rm=TRUE)
      ncsv$relWL <- (ncsv$obs-ncsv$meanSL)/1000
      ncsv$lat <- st_coordinates(stats[x,])[,2]
      ncsv$lon <- st_coordinates(stats[x,])[,1]
      ncsv$SLid <- stats$STid[x]
      ncsv$GLid <- stats$GLid[x]
      write.csv(ncsv,df,row.names=FALSE)
      ncsv
    })
  }else{
    return(NULL)
  }
  obs <- do.call(rbind,obs)|>
    ## get mean high tide
    group_by(SLid,day) |>
    mutate(HT = max(relWL,na.rm=TRUE)) |>
    ungroup()|>
    group_by(SLid) |>
    mutate(MSL = mean(relWL[time<min(stormdates,na.rm=TRUE)],na.rm=TRUE),
           MHT = mean(HT[time<min(stormdates,na.rm=TRUE)],na.rm=TRUE)) |>
    ungroup()|>
    filter(time>=min(stormdates),time<max(stormdates))|>
    group_by(SLid,time)|>
    filter(relWL==max(relWL,na.rm=TRUE))|>
    st_as_sf(coords=c("lon","lat"),crs=4326)
  obs
}


get_psmsl <- function(storm){
  statdat <- readLines("http://www.psmsl.org/data/obtaining/catalogue.dat")
  statlns <- grep("STATION ID",statdat)-1
  statids <- lapply(1:length(statlns),function(x){
    lne <- strsplit(statdat[statlns[x]],"  ")[[1]]
    lne <- lne[lne!=""]
    end <- grep("\\?",lne)
    lne <- lne[1:(end-1)]
    latlon <-as.numeric(unlist(regmatches(lne[(length(lne)-1):length(lne)],gregexpr("[-]{0,1}[[:digit:]]+\\.{0,1}[[:digit:]]*",lne[(length(lne)-1):length(lne)]))))
    if (length(latlon)==2){
      if (grepl("S",lne[2]))latlon[1] <- -1*latlon[1]
      if (grepl("W",lne[3]))latlon[2] <- -1*latlon[2]
      if (x==length(statlns)) id <- statdat[(statlns[x]+1):length(statdat)]
      else id <- statdat[(statlns[x]+1):(statlns[x+1]-1)]
      dates <- grep("DATA FOR",id,value=TRUE)
      if (length(dates)>0){
        dates <- strsplit(dates,"-")
        dates <- lapply(dates, function(x) c(substr(x[1],nchar(x[1])-4,nchar(x[1])),x[2]))
        if (length(dates)>1) dates <- data.frame(mindate=dates[[1]][1],maxdate=dates[[1]][2],minRLRdate=dates[[2]][1],maxRLRdate=dates[[2]][1])
        else dates <- data.frame(mindate=dates[[1]][1],maxdate=dates[[1]][2],minRLRdate=NA,maxRLRdate=NA)
        id <- as.numeric(gsub("\\D+", "", id[1]))
        id_name <- gsub("[0-9]", "",lne[1])
        id_name <- trimws(id_name)
        return(st_as_sf(cbind(data.frame(ID=id,name=id_name,lat=latlon[1],lon=latlon[2]),dates),coords=c("lon","lat"),crs=4326))
      }
    }
  })
  statids <- do.call(rbind,statids)
  roci <- storm |> pull(contains("CONS_ROCI"))|>mean(na.rm=TRUE)
  extnt <- st_transform(st_union(st_geometry(st_buffer(storm,as.numeric(roci)*1852))),4326)
  stats <- st_crop(statids,extnt) |>
    mutate(mindate=as.Date(paste0(mindate,"-01-01")),
           maxdate=as.Date(paste0(maxdate,"-12-31")))
  stats <- stats |>
    filter(mindate<min(as.Date(storm$ISO_TIME)),maxdate>max(as.Date(storm$ISO_TIME)))
  if (length(stats)>0){
    statobs <- lapply(1:nrow(stats),function(x){

    })
  }
}

